configuration.jsScript:
/**
 * Shadow State Conflict Detection Script
 *
 * Reads desired state (SHARED) and reported state (CLIENT) from metadata.
 * Computes sync_status and emits a CLIENT attribute update.
 *
 * sync_status values:
 *   'SYNCED'      — desired == reported for all actuators
 *   'OUT_OF_SYNC' — at least one actuator differs
 *   'PENDING'     — device last_seen is 0 (never connected)
 */

var desiredHvac   = metadata.desired_hvac   || 'OFF';
var desiredDimmer = parseInt(metadata.desired_dimmer || '50', 10);
var reportedHvac  = metadata.reported_hvac  || 'OFF';
var reportedDimmer= parseInt(metadata.reported_dimmer|| '50', 10);
var lastSeen      = parseInt(metadata.last_seen || '0', 10);

var syncStatus = 'SYNCED';

if (lastSeen === 0) {
    syncStatus = 'PENDING';  // Device never reported
} else if (desiredHvac !== reportedHvac || desiredDimmer !== reportedDimmer) {
    syncStatus = 'OUT_OF_SYNC';
}

// Emit sync_status as a CLIENT attribute update on this device
msg = {
    sync_status:      syncStatus,
    desired_hvac:     desiredHvac,
    desired_dimmer:   desiredDimmer,
    reported_hvac:    reportedHvac,
    reported_dimmer:  reportedDimmer,
    last_seen:        new Date().getTime()
};

msgType = 'POST_ATTRIBUTES_REQUEST';

return {msg: msg, metadata: metadata, msgType: msgType};

/**
 * Build southbound RPC payload for HVAC re-sync.
 * Uses desired_hvac from metadata (already loaded from SHARED_SCOPE).
 */
var desiredHvac = metadata.desired_hvac || 'OFF';

msg = {
    method: 'setHvac',
    params: desiredHvac
};

return {msg: msg, metadata: metadata, msgType: 'RPC_CALL_FROM_SERVER_TO_DEVICE'};

/**
 * Build southbound RPC payload for dimmer re-sync.
 */
var desiredDimmer = parseInt(metadata.desired_dimmer || '50', 10);

msg = {
    method: 'setDimmer',
    params: desiredDimmer
};

return {msg: msg, metadata: metadata, msgType: 'RPC_CALL_FROM_SERVER_TO_DEVICE'};
